<template>
  <v-overlay :value="open" class="AppNavDrawer" opacity="0.9">
    <v-container fluid>
      <v-row>
        <v-col>
          <v-btn icon @click="$emit('close')" fixed top right class="mt-n1 mr-n1">
            <v-icon>mdi-close</v-icon>
          </v-btn>
        </v-col>
      </v-row>

      <v-row>
        <v-col class="text-center">
          <router-link @click.native="$emit('close')" :to="{name: 'home'}" class="link">Home</router-link>
        </v-col>
      </v-row>
      <v-row v-for="link in links" :key="link.routeName">
        <v-col class="text-center">
          <router-link
            @click.native="$emit('close')"
            :to="{name: link.routeName}"
            class="link"
          >{{link.text}}</router-link>
        </v-col>
      </v-row>
      <v-row>
        <v-col class="text-center">
          <a
            :href="link.url"
            target="_blank"
            class="link px-2"
            v-for="link in socials"
            :key="link.url"
            @click="$emit('close')"
          >
            <v-icon>{{link.icon}}</v-icon>
          </a>
        </v-col>
      </v-row>
    </v-container>
  </v-overlay>
</template>

<script>
export default {
  name: "AppNavDrawer",
  props: {
    open: {
      type: Boolean,
      default: false
    },
    links: {
      type: Array,
      required: true
    },
    socials: {
      type: Array,
      required: true
    }
  }
};
</script>

<style scoped>
.link {
  font-family: "ARegular";
  color: white;
  font-size: 2rem;
}
</style>